CREATE TYPE "user_role" AS ENUM (
  'admin',
  'issuer',
  'student'
);

CREATE TYPE "credential_status" AS ENUM (
  'active',
  'revoked',
  'expired'
);

CREATE TYPE "verification_result" AS ENUM (
  'valid',
  'invalid_signature',
  'tampered',
  'revoked',
  'expired',
  'not_found',
  'ipfs_unreachable'
);

CREATE TYPE "wallet_status" AS ENUM (
  'active',
  'rotated',
  'revoked'
);

CREATE TABLE "credential_types" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "code" varchar(40) UNIQUE NOT NULL,
  "name" varchar(120) NOT NULL,
  "description" text,
  "allows_expiration" boolean NOT NULL DEFAULT false,
  "jsonld_context_url" varchar(500) NOT NULL,
  "schema_version" varchar(20) NOT NULL DEFAULT '1.0',
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "institutions" (
  "id" uuid PRIMARY KEY DEFAULT (gen_random_uuid()),
  "code" varchar(40) UNIQUE NOT NULL,
  "legal_name" varchar(200) NOT NULL,
  "display_name" varchar(120) NOT NULL,
  "did" varchar(200) UNIQUE NOT NULL,
  "issuer_wallet_address" varchar(42) UNIQUE NOT NULL,
  "public_key" text NOT NULL,
  "country_code" char(2) NOT NULL DEFAULT 'CL',
  "website_url" varchar(300),
  "is_active" boolean NOT NULL DEFAULT true,
  "registered_at" timestamp NOT NULL DEFAULT (now()),
  "deactivated_at" timestamp
);

CREATE TABLE "users" (
  "id" uuid PRIMARY KEY DEFAULT (gen_random_uuid()),
  "wallet_address" varchar(42) UNIQUE NOT NULL,
  "did" varchar(200) UNIQUE NOT NULL,
  "email" varchar(200) UNIQUE,
  "display_name" varchar(120),
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamp NOT NULL DEFAULT (now()),
  "last_login_at" timestamp
);

CREATE TABLE "institution_users" (
  "id" uuid PRIMARY KEY DEFAULT (gen_random_uuid()),
  "institution_id" uuid NOT NULL,
  "user_id" uuid NOT NULL,
  "role" user_role NOT NULL,
  "granted_by_user_id" uuid,
  "granted_at" timestamp NOT NULL DEFAULT (now()),
  "revoked_at" timestamp
);

CREATE TABLE "students" (
  "id" uuid PRIMARY KEY DEFAULT (gen_random_uuid()),
  "institution_id" uuid NOT NULL,
  "external_reference" varchar(80),
  "enrollment_year" int,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "student_wallets" (
  "id" uuid PRIMARY KEY DEFAULT (gen_random_uuid()),
  "student_id" uuid NOT NULL,
  "wallet_address" varchar(42) NOT NULL,
  "did" varchar(200) NOT NULL,
  "status" wallet_status NOT NULL DEFAULT 'active',
  "is_primary" boolean NOT NULL DEFAULT true,
  "activated_at" timestamp NOT NULL DEFAULT (now()),
  "rotated_at" timestamp,
  "rotation_reason" varchar(80)
);

CREATE TABLE "careers" (
  "id" uuid PRIMARY KEY DEFAULT (gen_random_uuid()),
  "institution_id" uuid NOT NULL,
  "code" varchar(40) NOT NULL,
  "name" varchar(200) NOT NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "credentials" (
  "id" uuid PRIMARY KEY DEFAULT (gen_random_uuid()),
  "institution_id" uuid NOT NULL,
  "credential_type_id" int NOT NULL,
  "student_id" uuid NOT NULL,
  "career_id" uuid,
  "issued_to_wallet_id" uuid NOT NULL,
  "subject_did" varchar(200) NOT NULL,
  "issuer_did" varchar(200) NOT NULL,
  "ipfs_cid" varchar(80) UNIQUE NOT NULL,
  "ipfs_gateway_url" varchar(500) NOT NULL,
  "content_hash" char(66) UNIQUE NOT NULL,
  "transaction_hash" char(66) UNIQUE NOT NULL,
  "block_number" bigint NOT NULL,
  "chain_id" int NOT NULL DEFAULT 11155111,
  "eip712_signature" varchar(132) NOT NULL,
  "status" credential_status NOT NULL DEFAULT 'active',
  "issued_at" timestamp NOT NULL DEFAULT (now()),
  "expires_at" timestamp,
  "revoked_at" timestamp,
  "revoked_by_user_id" uuid,
  "revocation_reason" text,
  "revocation_tx_hash" char(66),
  "created_at" timestamp NOT NULL DEFAULT (now()),
  "metadata" jsonb
);

CREATE TABLE "verification_logs" (
  "id" uuid PRIMARY KEY DEFAULT (gen_random_uuid()),
  "credential_id" uuid,
  "credential_id_query" varchar(80) NOT NULL,
  "result" verification_result NOT NULL,
  "error_detail" varchar(500),
  "verifier_ip" inet NOT NULL,
  "verifier_user_agent" varchar(500),
  "verifier_country" char(2),
  "verifier_referer" varchar(500),
  "verified_at" timestamp NOT NULL DEFAULT (now()),
  "duration_ms" int,
  "signature_valid" boolean,
  "hash_matches" boolean,
  "on_chain_exists" boolean,
  "not_revoked" boolean,
  "not_expired" boolean
);

CREATE TABLE "audit_logs" (
  "id" BIGSERIAL PRIMARY KEY,
  "institution_id" uuid,
  "actor_user_id" uuid,
  "actor_wallet_address" varchar(42),
  "action" varchar(80) NOT NULL,
  "entity_type" varchar(60) NOT NULL,
  "entity_id" varchar(80) NOT NULL,
  "success" boolean NOT NULL,
  "error_message" text,
  "ip_address" inet,
  "user_agent" varchar(500),
  "request_id" uuid,
  "payload" jsonb,
  "created_at" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "institution_metrics_daily" (
  "id" BIGSERIAL PRIMARY KEY,
  "institution_id" uuid NOT NULL,
  "metric_date" date NOT NULL,
  "credentials_issued" int NOT NULL DEFAULT 0,
  "credentials_revoked" int NOT NULL DEFAULT 0,
  "verifications_total" int NOT NULL DEFAULT 0,
  "verifications_valid" int NOT NULL DEFAULT 0,
  "verifications_invalid" int NOT NULL DEFAULT 0,
  "unique_students_active" int NOT NULL DEFAULT 0,
  "computed_at" timestamp NOT NULL DEFAULT (now())
);

CREATE TABLE "auth_challenges" (
  "id" uuid PRIMARY KEY DEFAULT (gen_random_uuid()),
  "nonce" varchar(40) UNIQUE NOT NULL,
  "wallet_address" varchar(42),
  "chain_id" int NOT NULL DEFAULT 11155111,
  "issued_at" timestamp NOT NULL DEFAULT (now()),
  "expires_at" timestamp NOT NULL,
  "consumed_at" timestamp
);

