COMMENT ON TABLE "credential_types" IS 'Catálogo de los 4 tipos del MVP: título, certificado de notas, certificación, diploma';

COMMENT ON COLUMN "credential_types"."code" IS 'Ej: TITULO, NOTAS, CERTIFICACION, DIPLOMA';

COMMENT ON COLUMN "credential_types"."allows_expiration" IS 'Si false, expires_at debe ser null';

COMMENT ON COLUMN "credential_types"."jsonld_context_url" IS 'URL del @context W3C para este tipo';

COMMENT ON TABLE "institutions" IS 'Cada institución es un tenant independiente. La clave privada NUNCA se almacena en BD.';

COMMENT ON COLUMN "institutions"."code" IS 'Identificador corto: DUOC, UCH, etc.';

COMMENT ON COLUMN "institutions"."did" IS 'DID del emisor institucional, ej: did:ethr:sepolia:0x...';

COMMENT ON COLUMN "institutions"."issuer_wallet_address" IS 'Dirección Ethereum del emisor (0x + 40 hex)';

COMMENT ON COLUMN "institutions"."public_key" IS 'Clave pública para verificación de firmas';

COMMENT ON COLUMN "institutions"."deactivated_at" IS 'Nullable. Si tiene valor, no puede emitir nuevas credenciales';

COMMENT ON TABLE "users" IS 'Usuario administrativo o emisor. Los alumnos viven en una tabla separada (anonimato máximo).';

COMMENT ON COLUMN "users"."wallet_address" IS 'Dirección Ethereum, autenticación vía SIWE';

COMMENT ON COLUMN "users"."did" IS 'did:ethr:sepolia:0x...';

COMMENT ON COLUMN "users"."email" IS 'Opcional. Solo para notificaciones administrativas, no para login';

COMMENT ON COLUMN "users"."display_name" IS 'Opcional. Solo para UI';

COMMENT ON TABLE "institution_users" IS 'Relación N:M entre usuarios e instituciones con rol específico';

COMMENT ON COLUMN "institution_users"."granted_by_user_id" IS 'Quién asignó este rol';

COMMENT ON COLUMN "institution_users"."revoked_at" IS 'Si tiene valor, el rol está inactivo';

COMMENT ON TABLE "students" IS 'Estudiante sin datos personales. La identidad real solo existe dentro de la VC en IPFS y en el SIS interno de la institución.';

COMMENT ON COLUMN "students"."external_reference" IS 'Ej: matrícula, RUT enmascarado, ID interno del SIS de la institución';

COMMENT ON COLUMN "students"."enrollment_year" IS 'Año de matrícula';

COMMENT ON TABLE "student_wallets" IS 'Historial de wallets de un estudiante. Las credenciales emitidas a wallets antiguas siguen siendo válidas.';

COMMENT ON COLUMN "student_wallets"."wallet_address" IS 'Dirección Ethereum del estudiante';

COMMENT ON COLUMN "student_wallets"."did" IS 'did:ethr:sepolia:0x... derivado de la wallet';

COMMENT ON COLUMN "student_wallets"."is_primary" IS 'Solo una wallet activa puede ser primaria por estudiante';

COMMENT ON COLUMN "student_wallets"."rotated_at" IS 'Cuándo se reemplazó por una nueva wallet';

COMMENT ON COLUMN "student_wallets"."rotation_reason" IS 'Motivo: compromised, voluntary, lost, etc.';

COMMENT ON TABLE "careers" IS 'Catálogo simple de carreras por institución. Sin versionado de planes de estudio (trabajo futuro).';

COMMENT ON COLUMN "careers"."code" IS 'Código interno: ING-SW, ENF, etc.';

COMMENT ON TABLE "credentials" IS 'Una credencial = un VC emitido. Datos personales NO se almacenan aquí, solo en el JSON-LD que vive en IPFS.';

COMMENT ON COLUMN "credentials"."id" IS 'UUID que también es el credentialId del VC';

COMMENT ON COLUMN "credentials"."career_id" IS 'Nullable: no todos los tipos requieren carrera (ej: diploma)';

COMMENT ON COLUMN "credentials"."issued_to_wallet_id" IS 'A qué wallet específica se emitió';

COMMENT ON COLUMN "credentials"."subject_did" IS 'DID del estudiante al momento de la emisión';

COMMENT ON COLUMN "credentials"."issuer_did" IS 'DID de la institución';

COMMENT ON COLUMN "credentials"."ipfs_cid" IS 'Content Identifier en IPFS, ej: bafybeig...';

COMMENT ON COLUMN "credentials"."ipfs_gateway_url" IS 'URL pública del gateway IPFS para acceso rápido';

COMMENT ON COLUMN "credentials"."content_hash" IS 'SHA-256 del JSON-LD, formato 0x + 64 hex';

COMMENT ON COLUMN "credentials"."transaction_hash" IS 'Hash de la tx en Sepolia, formato 0x + 64 hex';

COMMENT ON COLUMN "credentials"."block_number" IS 'Bloque donde se registró la credencial';

COMMENT ON COLUMN "credentials"."chain_id" IS 'Sepolia testnet';

COMMENT ON COLUMN "credentials"."eip712_signature" IS '0x + 130 hex = r || s || v';

COMMENT ON COLUMN "credentials"."expires_at" IS 'Nullable. Solo para tipos con allows_expiration = true';

COMMENT ON COLUMN "credentials"."revoked_at" IS 'Nullable. Si tiene valor, la credencial está revocada';

COMMENT ON COLUMN "credentials"."revoked_by_user_id" IS 'Usuario que ejecutó la revocación';

COMMENT ON COLUMN "credentials"."revocation_reason" IS 'Motivo de la revocación';

COMMENT ON COLUMN "credentials"."revocation_tx_hash" IS 'Hash de la tx de revocación en blockchain';

COMMENT ON COLUMN "credentials"."metadata" IS 'Datos adicionales no críticos: número de título, promedio, etc. (cache de lo que está en IPFS)';

COMMENT ON TABLE "verification_logs" IS 'Cada intento de verificación se registra completo. Sin datos del verificador identificables, solo metadatos técnicos.';

COMMENT ON COLUMN "verification_logs"."credential_id" IS 'Nullable: si no se encontró la credencial';

COMMENT ON COLUMN "verification_logs"."credential_id_query" IS 'ID consultado, incluso si no existe (para auditoría de intentos)';

COMMENT ON COLUMN "verification_logs"."error_detail" IS 'Detalle técnico del error, sin datos sensibles';

COMMENT ON COLUMN "verification_logs"."verifier_ip" IS 'IP del verificador anónimo';

COMMENT ON COLUMN "verification_logs"."verifier_country" IS 'Inferido por geoip';

COMMENT ON COLUMN "verification_logs"."verifier_referer" IS 'Origen de la verificación: QR scanner, app externa, etc.';

COMMENT ON COLUMN "verification_logs"."duration_ms" IS 'Tiempo total de la verificación end-to-end';

COMMENT ON COLUMN "verification_logs"."signature_valid" IS 'Pasó la verificación de firma EIP-712';

COMMENT ON COLUMN "verification_logs"."hash_matches" IS 'El hash on-chain coincide con el IPFS';

COMMENT ON COLUMN "verification_logs"."on_chain_exists" IS 'La credencial existe en la blockchain';

COMMENT ON COLUMN "verification_logs"."not_revoked" IS 'La credencial no está revocada';

COMMENT ON COLUMN "verification_logs"."not_expired" IS 'La credencial no está expirada';

COMMENT ON TABLE "audit_logs" IS 'Log inmutable de todas las operaciones administrativas. Append-only por convención.';

COMMENT ON COLUMN "audit_logs"."actor_user_id" IS 'Usuario que realizó la acción';

COMMENT ON COLUMN "audit_logs"."actor_wallet_address" IS 'Dirección que firmó la acción';

COMMENT ON COLUMN "audit_logs"."action" IS 'Ej: credential.issued, credential.revoked, role.granted';

COMMENT ON COLUMN "audit_logs"."entity_type" IS 'credential, user, role, institution, etc.';

COMMENT ON COLUMN "audit_logs"."request_id" IS 'Trace ID para correlación con logs estructurados';

COMMENT ON COLUMN "audit_logs"."payload" IS 'Snapshot de los datos relevantes, redactado de PII';

COMMENT ON TABLE "institution_metrics_daily" IS 'Snapshot diario de métricas por institución. Calculado por job nocturno.';

COMMENT ON TABLE "auth_challenges" IS 'Reto SIWE para autenticación. Actualmente en memoria, pero documentado en BD para futuro multi-instance.';

COMMENT ON COLUMN "auth_challenges"."wallet_address" IS 'Nullable hasta que se consuma';

COMMENT ON COLUMN "auth_challenges"."consumed_at" IS 'Nullable. Si tiene valor, el nonce fue usado';

ALTER TABLE "institution_users" ADD FOREIGN KEY ("institution_id") REFERENCES "institutions" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "institution_users" ADD FOREIGN KEY ("user_id") REFERENCES "users" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "institution_users" ADD FOREIGN KEY ("granted_by_user_id") REFERENCES "users" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "students" ADD FOREIGN KEY ("institution_id") REFERENCES "institutions" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "student_wallets" ADD FOREIGN KEY ("student_id") REFERENCES "students" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "careers" ADD FOREIGN KEY ("institution_id") REFERENCES "institutions" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "credentials" ADD FOREIGN KEY ("institution_id") REFERENCES "institutions" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "credentials" ADD FOREIGN KEY ("credential_type_id") REFERENCES "credential_types" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "credentials" ADD FOREIGN KEY ("student_id") REFERENCES "students" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "credentials" ADD FOREIGN KEY ("career_id") REFERENCES "careers" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "credentials" ADD FOREIGN KEY ("issued_to_wallet_id") REFERENCES "student_wallets" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "credentials" ADD FOREIGN KEY ("revoked_by_user_id") REFERENCES "users" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "verification_logs" ADD FOREIGN KEY ("credential_id") REFERENCES "credentials" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "audit_logs" ADD FOREIGN KEY ("institution_id") REFERENCES "institutions" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "audit_logs" ADD FOREIGN KEY ("actor_user_id") REFERENCES "users" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "institution_metrics_daily" ADD FOREIGN KEY ("institution_id") REFERENCES "institutions" ("id") DEFERRABLE INITIALLY IMMEDIATE;
